import{c as i,Q as l,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"出使锡耶纳","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/50-出使锡耶纳.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/50-出使锡耶纳.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/50-出使锡耶纳.md"};function c(s,a,n,m,d,p){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使锡耶纳",tabindex:"-1"},[t("出使锡耶纳 "),e("a",{class:"header-anchor",href:"#出使锡耶纳","aria-label":'Permalink to "出使锡耶纳"'},"​")],-1),e("p",null,"出使锡耶纳 和其他同一阶层的人，讨论了类似情况下人们所习惯的居住环境。他们回 答说，市政当局已经派去了6个人，以迎接特使并向他致敬。具体的安排 如下：特使本人和他的四五十名随身侍从或是住在潘多尔福的住所，或是 住在主教的宫殿里。他们的花费由接待方支付。其余的随从和他们的马匹 将住在旅馆里。这里旅馆的老板们已经被通知去做好必要的准备工作。现 在我们还不知道，他们的花费是由市政当局支付，还是由他们自己支付。 老板们在这一点上目前还没有得到解释。不过，老板们看到市政当局是多 么看重特使，也看到他们希望他能够保护他们在德意志的利益。因此，老 板们相信市政当局会支付一切花费。但他们对此还不能确定，而且他们也 不知道本国的其他地方对此是怎么做的。因此，我在这一点上没有什么其 他可说的了。但我明白将会和特使同处一地，一旦获得关于这些问题的充 分信息，就会给你们去信。我也无法告诉你们特使随员中骑兵的数目，因 为有人说是不到100人，而其他人则说是200人。但前者更为可信。总之， 就像我之前说过的，诸位大人在40小时内将会知道准确的人员数字、这 里接待他们的规格，以及他们抵达你们领地的时间。我不会向特使的管家 索要随员的名单，因为假如你们发现他实际的随从人数比名单所说要多的 话，会引起你们的尴尬。我不想导致你们的不快，因此把这个问题完全留 给诸位大人自己决定。 之前从卢西尼亚诺传来消息，说该镇由于惧怕基亚纳谷地的人，已经 决定紧闭城门。为此，巴利阿今天在这里举行了欢快的聚会。据我所听 说，对于皇帝的到来，卢西尼亚诺的人们就像过节一样高兴，因为他们都 希望这件事情发生。我向诸位大人提及此事，是因为在这类事件中，人民 的意志通常与其长官的意志不同。再会!",-1),e("p",null,"锡耶纳，1507年8月10日 仆尼科洛 · 马基雅维利，国务秘书",-1),e("p",null,"政务与外交著作 Legazioni,commissarie,scritti di governo",-1)])])}const f=i(o,[["render",c]]);export{_ as __pageData,f as default};
